unpivoting_wide_csv_to_tall.unpivot_m_code:
// Full M query: load wide CSV from SharePoint, unpivot to tall format
let
    // ── 1. Connect to SharePoint folder ──────────────────────────────
    Source = SharePoint.Files("https://contoso.sharepoint.com/sites/Security", [ApiVersion=15]),
    FilteredFiles = Table.SelectRows(Source, each Text.Contains([Folder Path], "/Reports/Monthly/")),
    CSVOnly = Table.SelectRows(FilteredFiles, each [Extension] = ".csv"),

    // ── 2. Add filename metadata before expanding ─────────────────────
    AddFileName = Table.AddColumn(CSVOnly, "SourceFile", each [Name], type text),

    // ── 3. Parse and promote headers for each file ────────────────────
    ParseCSV = Table.AddColumn(AddFileName, "Data",
        each Table.PromoteHeaders(
            Csv.Document([Content], [Delimiter=",", Encoding=65001])
        )
    ),

    // ── 4. Expand all CSV rows ────────────────────────────────────────
    SampleCols = Table.ColumnNames(ParseCSV{0}[Data]),
    Expanded = Table.ExpandTableColumn(ParseCSV, "Data", SampleCols),

    // ── 5. Remove SharePoint metadata columns ─────────────────────────
    Cleaned = Table.RemoveColumns(Expanded,
        {"Content","Extension","Date accessed","Date modified",
         "Date created","Attributes","Folder Path"}),

    // ── 6. Set date column type ───────────────────────────────────────
    TypedDate = Table.TransformColumnTypes(Cleaned, {{"Date", type date}}),

    // ── 7. UNPIVOT: keep Date and SourceFile fixed, pivot everything else
    Unpivoted = Table.UnpivotOtherColumns(TypedDate, {"Date", "SourceFile"}, "MetricName", "Value"),

    // ── 8. Cast Value to integer ──────────────────────────────────────
    TypedValue = Table.TransformColumnTypes(Unpivoted, {{"Value", Int64.Type}}),

    // ── 9. Add YearMonthKey for join to DateTable ─────────────────────
    AddKey = Table.AddColumn(TypedValue, "YearMonthKey",
        each Date.Year([Date]) * 100 + Date.Month([Date]),
        Int64.Type),

    // ── 10. Add MetricID by lookup (join to MetricDim values) ──────────
    // Option A: keep MetricName as text and join on name in the relationship
    // Option B: replace MetricName with integer ID here (more efficient):
    MetricIDLookup = [
        #"Sev5" = 1, #"Sev4" = 2, #"External" = 3,
        #"Internal" = 4, #"Alerts" = 5
    ],
    AddMetricID = Table.AddColumn(TypedValue, "MetricID",
        each try Record.Field(MetricIDLookup, [MetricName]) otherwise null,
        Int64.Type)
in
    AddMetricID

unpivoting_wide_csv_to_tall.selective_unpivot:
// Alternative: unpivot only specific columns by name
Unpivoted = Table.Unpivot(
    Source,
    {"Sev5", "Sev4", "External", "Internal", "Alerts"},  -- columns to unpivot
    "MetricName",  -- new attribute column name
    "Value"        -- new value column name
)
// Use this when the CSV has both metric columns AND other non-metric columns
// that should not be unpivoted (e.g. Region, Business Unit)

approach_single_fact_table.m_query_merge:
// Load monthly CSVs → unpivot → add PeriodType = "Monthly"
// Load quarterly CSVs → unpivot → add PeriodType = "Quarterly"
// Then combine:
SecuritySnapshots = Table.Combine({MonthlyFact, QuarterlyFact})

// Each fact row now has PeriodType which measures can filter by:
Quarterly Score =
    CALCULATE(
        [Metric Value],
        SecuritySnapshots[PeriodType] = "Quarterly"
    )

excel_files_vs_csv.excel_m_snippet:
// Replace the Csv.Document step with Excel.Workbook:
ParseExcel = Table.AddColumn(FilteredFiles, "Data",
    each let
        wb    = Excel.Workbook([Content], true, true),  -- true = use headers, true = use column names from first row
        sheet = wb{[Kind="Sheet", Name="Data"]}[Data]   -- get 'Data' sheet; use wb{0}[Data] for first sheet
    in sheet
),
// Then ExpandTableColumn as before

